        int left = 0, right = s.length();
        while (left < right) {
            if (s.charAt(left) != s.charAt(right)) return false;
            left++;
            right--;
        }
        return true;
    }
    public static void main(String[] args) {
        System.out.print(isPalindrome("racecar"));
    }
}

